CREATE TABLE t_p79235343_uplink_clone_website.cms_faq (
  id SERIAL PRIMARY KEY,
  sort_order INTEGER NOT NULL DEFAULT 0,
  question TEXT NOT NULL,
  answer TEXT NOT NULL,
  is_active BOOLEAN NOT NULL DEFAULT true,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

INSERT INTO t_p79235343_uplink_clone_website.cms_faq (sort_order, question, answer) VALUES
(1, 'Сколько стоит IT-аутсорсинг в Саратове?', 'Стоимость начинается от 7 000 ₽/мес — это абонентское обслуживание с фиксированной ценой. Точная сумма зависит от количества рабочих мест и набора услуг. Это до 40% дешевле, чем держать штатного системного администратора.'),
(2, 'Как быстро приедет системный администратор?', 'Реагирование на критические инциденты — выезд от 30 минут, удалённое подключение за 15 минут. Заявки принимаем 24/7 по телефону 8 (986) 986-01-36.'),
(3, 'Вы делаете монтаж видеонаблюдения под ключ?', 'Да. Берём на себя весь цикл: проектирование, поставка оборудования, монтаж IP и аналоговых камер для офиса, склада или магазина, настройка удалённого доступа и архива.'),
(4, 'Выполняете монтаж локальной сети (ЛВС/СКС)?', 'Да, выполняем полный цикл: проектирование, прокладка кабеля, монтаж коммутационного оборудования Mikrotik и Cisco, настройка корпоративной сети, тестирование и сертификация.'),
(5, 'Можно подключить IP-телефонию для бизнеса в Саратове?', 'Конечно. Настраиваем IP-АТС и виртуальные АТС (ВАТС), подключаем IP-телефоны, интегрируем с CRM-системами, администрируем Asterisk и FreePBX.'),
(6, 'Работаете ли вы с малым бизнесом?', 'Да, малый и средний бизнес — наша основная аудитория. IT-аутсорсинг особенно выгоден небольшим компаниям: не нужен штатный сотрудник, платите только за реальный объём работ.');
